counter += 1 // ✅

// Value type — let freezes the whole value
struct Point { var x: Int; var y: Int }
let p = Point(x: 1, y: 2)
// p.x = 5 // ❌ cannot mutate stored property

// Reference type — let only freezes the reference
class Counter { var value = 0 }
let c = Counter()
c.value = 10 // ✅ allowed
// c = Counter() // ❌ cannot reassign

var name: String? = "Alice"

// if let
if let unwrapped = name {
  print(unwrapped.uppercased())
}

// guard let — early exit
func greet(_ name: String?) {
  guard let name else { return }
  print("Hello, \(name)")
}

// nil-coalescing
let display = name ?? "Guest"

// optional chaining
let length = name?.count // Int?

// map / flatMap
let upper = name.map { $0.uppercased() }

// Force unwrap — only when impossible to be nil
let url = URL(string: "https://apple.com")! // OK — literal

// Implicitly unwrapped optional — used for IBOutlets, lifecycle vars
@IBOutlet var label: UILabel!

// Value type
struct Point { var x: Int; var y: Int }
var a = Point(x: 1, y: 2)
var b = a       // copy
b.x = 99
print(a.x)      // 1 — unchanged

// Reference type
class Counter { var value = 0 }
let c1 = Counter()
let c2 = c1     // same instance
c2.value = 10
print(c1.value) // 10

// Identity check (only for classes)
print(c1 === c2) // true — same reference

// Copy-on-write — Array looks like value but is cheap to copy
var arr1 = [1,2,3]
var arr2 = arr1      // logical copy, shared buffer
arr2.append(4)       // triggers actual copy now
print(arr1)          // [1,2,3]

// Function-typed value
let add: (Int, Int) -> Int = { a, b in a + b }

// Trailing closure + shorthand
let doubled = [1,2,3].map { $0 * 2 } // [2,4,6]

// Strong capture (default) — risk of retain cycle
class ViewController {
  var onDone: (() -> Void)?
  func setup() {
    onDone = { self.refresh() } // ⚠️ self captured strongly
  }
  func refresh() {}
}

// [weak self] — break the cycle
class Safe {
  var onDone: (() -> Void)?
  func setup() {
    onDone = { [weak self] in
      self?.refresh()
    }
  }
  func refresh() {}
}

// [unowned self] — non-optional, crashes if self is gone
// Use when the closure cannot outlive self (e.g. synchronous UIView animations)
UIView.animate(withDuration: 0.3) { [unowned self] in
  self.alpha = 1
}

// @escaping — closure stored / called later
func fetch(completion: @escaping (Data) -> Void) { /* ... */ }

// Array
var fruits = ["apple", "banana", "cherry"]
fruits.append("date")
let uppercased = fruits.map { $0.uppercased() }
let long = fruits.filter { $0.count > 5 }
let joined = fruits.joined(separator: ", ")

// Set
var tags: Set<String> = ["swift", "ios"]
tags.insert("swift")        // no duplicate
let a: Set = [1,2,3], b: Set = [3,4,5]
print(a.union(b))         // {1,2,3,4,5}
print(a.intersection(b))  // {3}
print(a.subtracting(b))   // {1,2}

// Dictionary
var scores: [String: Int] = ["Alice": 95, "Bob": 87]
scores["Carol"] = 92
for (name, score) in scores {
  print("\(name): \(score)")
}
// Default lookup
let aliceScore = scores["Alice", default: 0]

// Group items into buckets
let words = ["apple", "ant", "bee", "banana"]
let byInitial = Dictionary(grouping: words, by: { $0.first! })

enum AuthError: Error {
  case invalidCredentials
  case networkDown
  case throttled(retryAfter: TimeInterval)
}

func login(_ email: String, _ password: String) throws -> User {
  guard !password.isEmpty else { throw AuthError.invalidCredentials }
  // ...
}

// Caller — propagate
func bootstrap() throws {
  let user = try login("alice@x.com", "hunter2")
  print(user)
}

// Caller — handle
do {
  let user = try login(email, password)
  display(user)
} catch AuthError.invalidCredentials {
  showInlineError()
} catch AuthError.throttled(let retry) {
  scheduleRetry(after: retry)
} catch {
  showGenericError(error)
}

// try? for optional
let user = try? login(email, password) // User?

// Result type — store outcome as a value
let outcome: Result<User, AuthError> = Result { try login(email, password) }
  .mapError { _ in .networkDown }
switch outcome {
case .success(let u): display(u)
case .failure(let e): showError(e)
}

// Typed throws (Swift 6+)
func fetch() throws(AuthError) -> User { /* compiler enforces only AuthError */ }

// Tuples
func minMax(_ xs: [Int]) -> (min: Int, max: Int)? {
  guard let first = xs.first else { return nil }
  var lo = first, hi = first
  for x in xs { if x < lo { lo = x }; if x > hi { hi = x } }
  return (lo, hi)
}
if let result = minMax([3,1,4,1,5,9]) {
  print(result.min, result.max) // 1 9
}

// Ranges
for i in 0..<3 { print(i) }      // 0 1 2
for i in 1...3 { print(i) }       // 1 2 3
let substring = "Hello"[..<"Hello".index("Hello".startIndex, offsetBy: 3)]

// One-sided ranges
let arr = [10,20,30,40,50]
print(arr[2...])   // 30,40,50
print(arr[...2])   // 10,20,30

